UPDATE agent_fix_queue SET status='resolved', resolved_at=now(), dismissed_reason='Same 2 historical DLQ rows from 2026-05-18 13:58 UTC rate-limit episode (TTL exceeded, 15min). Already root-caused: TTL bumped to 60min in email_send_state. User retried successfully via signup-fallback at 18:00 UTC. Probe re-fired only because failed_last_24h is a rolling 24h window.' WHERE status IN ('pending','triaged','proposed') AND (event_type ILIKE '%signup%' OR fingerprint ILIKE '%signup%');